import hashlib

def generate_signature(algorithm_name, content):
    hash_obj = hashlib.new(algorithm_name)
    hash_obj.update(content)
    return hash_obj.digest()

turn2_code:
import hashlib

def generate_signature(algorithm_name, content, secret):
    try:
        hash_obj = hashlib.new(algorithm_name)
        hash_obj.update(secret + content)
        return hash_obj.digest()
    except ValueError:
        raise ValueError(f"Unsupported algorithm: {algorithm_name}")

turn3_code:
import hashlib
import hmac

def generate_signature(algorithm_name, content, secret):
    try:
        return hmac.new(secret, content, algorithm_name).digest()
    except ValueError:
        raise ValueError(f"Unsupported algorithm: {algorithm_name}")
